What do you prefer for swiftshader (I still don't understand how it can compiles on amd64)
 - I patch third_party/swiftshader/third_party/llvm-7.0/configs/linux/include/llvm/Config/*
 - I create a new dir 'bsd' with our stuff in it:

--- third_party/swiftshader/third_party/llvm-7.0/BUILD.gn.orig  2019-04-15 16:11:25.681968000 +0200
+++ third_party/swiftshader/third_party/llvm-7.0/BUILD.gn       2019-04-15 12:02:01.926709000 +0200
@@ -98,7 +98,9 @@ llvm_include_dirs = [
   "configs/common/lib/Transforms/InstCombine/",
 ]

-if (is_linux) {
+if (is_bsd) {
+  llvm_include_dirs += [ "configs/bsd/include/" ]
+} else if (is_linux) {
   llvm_include_dirs += [ "configs/linux/include/" ]
 } else if (is_fuchsia) {
   llvm_include_dirs += [ "configs/fuchsia/include/" ]
